def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.3:
            score = (1 - ratio)**3 + np.sin(ratio * np.pi)
        elif 0.3 <= ratio < 0.6:
            score = np.log1p(ratio * 2) * 3 - np.sqrt(ratio)
        elif 0.6 <= ratio < 0.9:
            score = 1 / (1 + np.exp(-15 * (ratio - 0.75))) + np.cos(ratio * 5)
        else:
            score = np.tanh(10 * (ratio - 0.9)) + 0.5
        penalty = 0
        for j in range(1, 6):
            mod_val = ((item * j) % capacity)
            frac = mod_val / (capacity * j)
            if frac < 0.1:
                penalty += frac * 2
            elif 0.1 <= frac < 0.3:
                penalty += frac
            else:
                penalty += frac / (j + 1)
        extra_penalty = 0
        for k in range(1, 4):
            if ratio > 0.5 * k:
                extra_penalty += np.exp(-k * ratio) * k
            else:
                extra_penalty += np.log1p(k * ratio + 1) / (k + 1)
        if capacity % 2 == 0:
            priorities[i] = score + penalty + extra_penalty
        else:
            priorities[i] = score + penalty * 1.5 + extra_penalty * 0.8
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
